exec<arg_key>command</arg_key><arg_value># 检查 WAV 是否生成
Write-Host "[检查 WAV 文件]"
$wavPath = "E:\openclaw\workspace\swap\temp\neurosama_intro.wav"
$pngPath = "E:\openclaw\workspace\swap\temp\neurosama_camera.png"

if (Test-Path $wavPath) {
    Write-Host "[OK] WAV: $((Get-Item $wavPath).Length) bytes"
} else {
    Write-Host "[待生成] WAV"
}

if (Test-Path $pngPath) {
    Write-Host "[OK] PNG: $((Get-Item $pngPath).Length) bytes"
} else {
    Write-Host "[待生成] PNG"
}</arg_value><arg_key>timeout</arg_key><arg_value>15</arg_value></tool_call>
